INSERT INTO `job_requests` VALUES (1,'Cheoljin Kim','cheoljinkim@gmail.com','6097517595','Application for a position','Name: Cheoljin Kim, Ph.D.\nCitizenship: United States\nContact: cheoljinkim@gmail.com | +1-609-751-7595\nAddress: North Brunswick, NJ, USA\n________________________________________\nEDUCATION\n•	Ph.D. in Chemical and Biological Engineering, Seoul National University, Korea (2003–2008) \n•	Postdoctoral Research Scientist, Princeton University (2008–2010) \n•	Research Scientist, Rutgers University (2010–2011)\n________________________________________\nPROFESSIONAL EXPERIENCE\n•	Senior Principal Scientist, Access Bio (2023–2025)\n•	Director, Molecular Surface Technologies (2018–2023)\n•	Principal Scientist, Orthobond (2011–2018)\n•	Senior Research Scientist, SAMSUNG (until 2003)\n________________________________________\nRESEARCH INTERESTS\n•	Chemical synthesis, Nanoparticle synthesis & conjugation (CNB, gold, gold encapsulated polymer, selenium, chitosan, silver, etc.)\n•	Rapid diagnostic devices (COVID-19, Flu A&B, RSV, Malaria, Dengue, Strep A, TnI, etc.)\n•	Antibody engineering, biosensors, surface chemistry\n•	Drug discovery\n•	Drug/gene delivery, stem cells and cancer therapy\n•	Antibacterial and antithrombin coatings for medical devices\n•	FDA cGMP documentation (DHF, DMR, DHR)\n________________________________________\nMEMBERSHIPS\n•	Reviewer for Biomaterials Science, Royal Society of Chemistry\n•	Member of ACS, KSEA, and KASBP\n________________________________________\nTECHNICAL SKILLS\n•	Synthesis: Small molecules, Peptides, polymers, quorum-sensing antagonists\n•	Instrumentation: NMR, GC/MS, FT-IR, GPC, MALDI-TOF, microscope, Particle size analyzer, Nanodrop, UV-Vis spectrophotometer, TEM, SEM, AFM\n•	Surface chemistry: Depositions with phosphonic acid, silane, dopamine\n•	Nanotech: Quantum dots, magnetic nanoparticles (MNP), CNB, Gold NP, Gold encapsulation, Silver NP, Chitosan NP, Selenium NP\n•	Biosensors: pH, enzyme, UV, and cancer detection sensors\n________________________________________\nAWARDS\n•	Samsung \"Rose Grand Prize\" (1994) \n•	1st prize of ‘National Laboratory Enterprise Contest’, Small and Medium Business Administration’ and ‘Dongah Daily’ [1999]\n•	1st prize of ‘Best Paper Award’, Korean Society of Industrial and Engineering Chemistry [2006]\n•	Best Patent Awards, Seoul National University (2006)\n•	Founders’ & Chairman’s Awards, Orthobond (2012, 2016)\n•	14th Spine Technology Award (2020)\n•	Best Employee Award, Access Bio (2024)\n________________________________________\nPATENTS\n•	16 patents including US and international patents in antibacterial polymers, quorum sensing inhibitors, drug delivery, and surface adhesives.\n________________________________________\nPUBLICATIONS\n•	17 peer-reviewed articles in journals such as Applied Chemistry, Molecular Pharmaceutics, ACS Nano, Small, and Advanced Materials\n•	2 chemistry textbooks\n•	Numerous international and domestic conference presentations\n________________________________________\nSOFTWARE & TOOLS\n•	Scientific: ChemOffice, Molecular modeling (pyMOL)\n•	Creative: Adobe Premiere, Adobe Illustrator, Photoshop, CorelDraw\n•	MS Office Suite\n________________________________________\nHOBBIES & OTHER ACTIVITIES\n•	Song composition & producing, Electric guitar, drums, bass guitar (published 4 music albums, 35 songs)\n•	Ping pong, tennis\n•	Novelist and amateur filmmaker','1','2025-09-26 18:16:06','2025-09-26 18:16:06',2),(2,'Patrick Mcginley','pat.mcginley6@gmail.com','6096105132','Analytical Chemist Application','Patrick McGinley \nPhone: (609)-610-5132 \nEmail:  pat.mcginley6@gmail.com \n\nEducation \nMuhlenberg College, Allentown, PA \nB.S. Chemistry \n\nInstruments used: Very familiar with FT-IR, GC/MS, NMR, UV-Vis, XRF; familiar with DSC, HPLC, \nFluorometer, AA, ICP \nProficient in: Microsoft Word, Excel, PowerPoint \n\nWork Experience \nLuxottica (Lenscrafters), Freehold, NJ     \nLead Lab Technician - \n11/2021-11/2024 \n-Responsible for assisting in training and onboarding new associates, ensuring standards \nand proper techniques are communicated and upheld throughout lab \n-Took lead on audits from regional managers as well as product recalls and other \nadministrative work to ensure lab compliance with company practices \n-Worked with both lab manager and retail manager to ensure both sides of the store \nwere working efficiently together \n-Brought store lab rankings from Bottom 20% of region to Top 20% of region within 6 \nmonths. \n-Developed and improved on time-management skills to balance multiple jobs at once \nand ensure customer satisfaction in a fast-paced environment \n\nLuxottica (Lenscrafters), Watchung, NJ     \nLab Technician - \n1/2018-11/2021 \n-Responsible for production of eyewear through surfacing of lens blanks, maintenance \nand cleaning of laboratory equipment, and ensuring that all Good Manufacturing \nPractices (GMP) are followed to ensure the best product possible\n-Perform maintenance on lab equipment as required, including daily/weekly upkeep as \nwell as emergency repairs to prevent downtime of eyewear manufacturing \n-Multitasked various responsibilities to ensure steady flow of lab work, prioritize the \nappropriate tasks to make the most out of limited time, and ensure eyewear was \ndelivered to the customer in a timely fashion \n\nAshwin-Ushas Corporation, Marlboro, NJ     \nResearch Assistant  - \n11/2015-2/2016 \n-Worked in lens construction for sunglasses (better technology for transition lens)\nPlaced polyethylene sheet in deposition chamber along with solution and ran current \nacross polyethylene where solution would adhere to polyethylene to create lens \n-Lens was tested using UV-VIS to determine transmittance and kept for further testing if \nin acceptable parameters \nP-rototype system was created for large-scale lens production \n\nAbington Reldan Metals, Fairless Hills, PA     \nLab Chemist  - \n8/2015-11/2015 \n-X-rayed samples to see rough estimate of precious metals present (Pt, Au, Ag) and then \nperformed fire assay on samples to refine precious metals and determined \nconcentration in sample\n-Sample was received, labeled and weighed before placing into ceramic cup with lead \nflux \n-Sample was heated through fire assay to create lead button containing precious metals \n-Lead button was heated overnight to remove lead and leave precious metals remaining \n-Precious metals button was weighed to determine total mass of precious metals as well \nas percentage of overall sample \n-Button underwent acid baths as well as ICP to measure exact quantities of individual \nmetals','1','2025-09-27 00:20:54','2025-09-27 00:20:54',2),(3,'Luke Collier','2000lcollier@gmail.com','7323542328','Junior Analytical Chemist & Sourcing Associate Internship Application','Luke Matthew Collier – Curriculum Vitae\nUniversity of Michigan – Ann Arbor\nLife Sciences Institute\nDepartment of Chemistry\n210 Washtenaw Avenue\nAnn Arbor, MI 48109\nCell +1 (732) 354-2328\nlukecoll@umich.edu\nwww.linkedin.com/in/luke-m-collier\n\nResearch Interests: Mass Spectrometry, Natural Products Discovery, Multi-Omics\n\nEmployment\nJanuary 2023 –\nMay 2023 \nTouchCare\nResearch Analyst\n1161 Broad Street, Suite 114\nShrewsbury, NJ 07702\n\nSept. 2022 – January 2023\nTownship of Ocean Sewerage Authority\nChemist\n224 Roosevelt Avenue\nOakhurst, NJ 07755\n\nSummer 2022\nFlavor Materials International\nChemist\n10 Engelhard Avenue\nAvenel, NJ 07001\n\nEducation\n\nPresent: Chemistry Ph.D. Candidate\nAdvisor: Professor David H. Sherman\nUniversity of Michigan – Ann Arbor\nLife Sciences Institute\nDepartment of Chemistry\n210 Washtenaw Avenue\nAnn Arbor, MI 48109\n\nMay 2025 \nMaster of Science in Chemistry (Bioanalytical)\nAdvisor: Professor David H. Sherman\nUniversity of Michigan – Ann Arbor\nLife Sciences Institute\nDepartment of Chemistry\n210 Washtenaw Avenue\nAnn Arbor, MI 48109\n\nMay 2023\nBachelor of Science in Chemistry (ACS Certified)\nThesis: Influence of Microplastics on Aquatic and Human Ecosystems:\nA Three-Part Comprehensive Study Regarding Sample Extraction\nMethods, Speciation of Heavy Metal(loid)s, and Physical Mobility\nthrough Wastewater Treatment Plants\nAdvisor: Professor Tsanangurayi Tongesayi\nMonmouth University Honors School\nDepartment of Chemistry and Physics\n400 Cedar Avenue\nWest Long Branch, NJ 07764\n\nPublications\n1. Youssef, M. M.; Szot, C. W.; Folz, J.; Collier, L. M.; Kweon, H. K.; DeFiglia, S. A.; Ayad,\nM. F.; Hussein, L. A.; Abdel-Ghany, M. F.; Hakansson, K.* Electron Capture vs. Transfer\nDissociation for Site Determination of Tryptic Peptide Tyrosine Sulfation: Direct Detection\nof Fibrinogen Sulfation Sites and Identification of Novel Isobaric Interferences. J. Proteome\nRes. 2024, 23, 7, 2386-2396\n\nNational Conference Presentations\nFortified Sample Preparation and LC-MS/MS Enabled Methods for Comprehensive Dicamba\nHerbicide Analysis in Leaves, Nectar, and Pollen. Luke M. Collier, Sean Newmister, Joseph\nRedinger, Elise Kanefsky, Regina Baucom, David H. Sherman. American Society for Mass\nSpectrometry & Allied Topics Annual Conference, 2025. (Poster).\nImproved Liquid Chromatography and MS/MS Methods for Sulfopeptide Identification. Luke\nM. Collier, Menatallah M. Youssef, Kristina I. Håkansson. American Society for Mass\nSpectrometry & Allied Topics Annual Conference, 2024. (Poster).\nRevitalizing Community: Decreased COVID-19 Transmission and Mortality in Northeast, New\nJersey, as a Result of Improving Air Quality throughout the COVID-19 Pandemic. Luke M.\nCollier, National Collegiate Honors Council Annual Conference, 2022. (Poster).\nAir Quality Improvements in New Jersey, USA, During the COVID-19 Pandemic. Luke M.\nCollier, National Collegiate Honors Council Annual Conference, 2021. (Poster).\n\nRegional and Local Conference Presentations\nImproved Liquid Chromatography and MS/MS Methods for Sulfopeptide Identification. Luke\nM. Collier, Menatallah M. Youssef, Kristina I. Håkansson. Agilent Symposium on Measurement\nScience, 2024. (Poster).\nBiogeochemistry of Microplastics within Aquatic Environments in Regard to Extraction,\nTransport, and Interactions with Organisms. Luke M. Collier, Alexis M. Ferreira, Tsanangurayi\nTongesayi, Monmouth University School of Science Annual Research Symposium, 2023. (Poster).\nPhysical and Chemical Limitations Regarding Extraction Methods of Microplastics from\nConsumer and Commercial Soap Products. Luke M. Collier, Alexis M. Ferreira, Tsanangurayi\nTongesayi, Monmouth University Scholarship Week Research Symposium, 2022. (Poster).\nRevitalizing Community: Decreased COVID-19 Transmission and Mortality in Northeast, New\nJersey, as a Result of Improving Air Quality throughout the COVID-19 Pandemic. Luke M.\nCollier, Northeast Regional Honors Council Annual Conference, 2022. (Poster).\nPhysical and Chemical Advances and Limitations Regarding Extraction Methods of\nMicroplastics from Consumer and Commercial Soap Products. Luke M. Collier, Tsanangurayi\nTongesayi, Monmouth University School of Science Annual Research Symposium, 2021.\n(Podium via Zoom).\n\nProfessional Affiliations\nAmerican Chemical Society\nDivision of Agricultural and Food Chemistry\nDivision of Agrochemicals\nDivision of Analytical Chemistry\nDivision of Chemical Education\nDivision of Chemical Health and Safety\nDivision of Chemical Toxicology\nDivision of Environmental Chemistry\nAmerican Society for Mass Spectrometry\nProteomics\nMetabolomics\nFT-MS\nImaging Mass Spectrometry\nEnvironmental Chemistry and Emerging Contaminants\nPerfumer and Flavorist+\n\nSoftware and Programming Experience\nAgilent Technologies\nMassHunter\nQualitative Analysis\nQuantitative Analysis\nPersonalized Compound Database and Library\nMetabolomics Explorer\nThermoFisher Scientific\nXCalibur\nFree Style\nTrace Finder\nProteome Discoverer\nCompound Discoverer\nBioPharma Finder\nShimadzu\nLabSolutions\nGeneral Mass Spectrometry Software\nSkyLine\nmzMine\nMSConvert\nProtein Prospector\nGlobal Natural Product Social Molecular Networking (GNPS)\nNuclear Magnetic Resonance Data Analysis\nMnova (1D and 2D analysis)\n\nProgramming Languages\nR\nPython\nJulia\n\nReferences\n1. Professor David H. Sherman, Ph.D. – University of Michigan\ndavidhs@umich.edu\nHans W. Vahlteich Professor of Medicinal Chemistry\nProfessor of Medicinal Chemistry, College of Pharmacy\nProfessor of Microbiology and Immunology, UM Medical School\nProfessor of Chemistry, College of Literature, Science, and the Arts\nResearch Professor, Life Sciences Institute\n2. Professor Regina Baucom, Ph.D. – University of Michigan\nrsbaucom@umich.edu\nProfessor of Ecology and Evolutionary Biology, College of Literature, Science, and the Arts\n3. Professor Elizabeth Tibbetts, Ph.D. – University of Michigan\ntibbetts@umich.edu\nProfessor of Ecology and Evolutionary Biology, College of Literature, Science, and the Arts\n4. Professor Tsananguaryi Tongesayi, Ph.D. – Monmouth University\nttongesa@monmouth.edu\nChair, Department of Chemistry and Physics, School of Science\nProfessor of Analytical Chemistry, School of Science\n5. Dr. Wenqing Feng, Ph.D. – University of Michigan\nwendyfen@umich.edu\nDirector, Life Sciences Institute Mass Spectrometry Core','1','2025-10-02 02:14:40','2025-10-02 02:14:40',3),(4,'Binjal','Binjalpatel08@gmail.com','2019178965','Test','Test','1','2025-11-19 14:22:09','2025-11-19 14:22:09',3),(5,'gurpal singh','gurpalsingh@jwhglobal.com','7854785478','test','test','1','2025-11-19 14:22:27','2025-11-19 14:22:27',3),(6,'Alexander Bennett','piyushthakurjwh@gmail.com','1234567895','Testing','Name: Alexander Bennett\nEmail: alex.bennett@example.com\n\nPhone: +1 (312) 555-8274\nLocation: Chicago, IL, USA\n\nProfessional Summary\n\nHighly motivated Full Stack Web Developer with 4+ years of experience in building dynamic and high-performance web applications. Skilled in Laravel, PHP, JavaScript, MySQL, and REST APIs. Strong focus o