INSERT INTO `products` VALUES (7355,'1,1,1,3,5,5,5-HEPTAMETHYL-3-OCTYLTRISILOXANE','100001','GCC','17955-88-3','1','1113555-heptamethyl-3-octyltrisiloxane','QC: CLEAR COLORLESS, ODORLESS LIQUID',NULL,NULL,'SYN: SILCARE SILICONE 41M15, CAPRYLYLMETHYLSILICONE',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7356,'1,2-BENZODIHYDROPYRONE','100002','GCC','119-84-6','1','12-benzodihydropyrone','Colorless to light yellow liquid with sweetish floral (Jasmine Rose) odor.',NULL,'Used as an intermediate in the manufacturing of Polyester Plasticizers, Unsaturated Polyester Intermediates, Saturated Polyesters for Polyurethane coatings, surfactants, inks, solvents for natural and synthetic flavorings, and coupling agents in cellophane.','Dihydrocoumarin, BDHP, Hydrocoumarin; 1,2-Benzodihydropyrone','Keep container tightly closed when not in use. Store in a cool, dry, well-ventilated area away from incompatible substances.','[\"100 Gram HDPE Bottle\",\"10 kg. Pail\",\"50 kg. drum\"]','[\"Food & bev.\",\"industrial\"]','[\"Plasticizers\",\"Solvents\"]','C9H8O2','[\"Origin: Synthetic\",\"Shelf life: Two years from manufacture date.\",\"Freight Classification: NMFC 43940 SUB 2 CLASS 70 RV 2.15\",\"Kosher Status: Not Kosher\",\"Flash Point: 113 \\u00f8C (235 \\u00f8F)\",\"Melting Point: 25\\u00ff\\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: NO\",\"Molecular Weight: 90.12 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7357,'1,2-, C12-16, ETHOXYLATED PROPOXYLATED','100003','GCC','154248-98-3','1','12-c12-16-ethoxylated-propoxylated','QC: CLEAR YELOWISH LIQUID WITH LIGHT CHARACTERISTIC ODOR',NULL,NULL,'SYN: EUMULGIN L',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7358,'1-(2-CARBOXYLATOETHYL)-4,5-DIHYDRO-3-(2-HYDROXYETHYL)-2-ISOHEPTADECYL-1H-IMIDAZOLIUM','100004','GCC','68630-96-6','1','1-2-carboxylatoethyl-45-dihydro-3-2-hydroxyethyl-2','AMBER LIQUID',NULL,NULL,NULL,NULL,'[null]','[\"Cosmetics\"]','[\"Surfactants\"]','C25H48N2O3','[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7359,'12 HYDROXYSTEARIC ACID','100005','GCC','106-14-9','1','12-hydroxystearic-acid','Dull, yellow waxy solid with no color.',NULL,'It is often used in the manufacturing of lithium and calcium based greases. It is also used in the preparation of cosmetics, wax blends, polishers, inks, and paints.','12 Hydroxystearic Acid','Store in a cool, dry place away from strong oxidizing agents. (Melts at 70oC)','[\"250 Gram HDPE WM Bottle\",\"5 lb. HDPE WM Bottle\",\"5 kg. HDPE OH Pail\",\"25 lb. Fiber Drum\",\"50 lb. Fiber Drum\",\"50 lb. Bag\",\"1 lb. Bulk\"]','[\"Cosmetics\"]','[\"Fatty acids\"]','C18H36O3','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NMFC 145020 CLASS 65\",\"Kosher Status: Not Kosher\",\"Flash Point: 210OC\",\"Melting Point: 75-78\\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: NO\",\"Molecular Weight: 300.48 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7360,'1,3 BUTYLENE GLYCOL','100006','GCC','107-88-0','1','13-butylene-glycol','Clear Colorless syrupy liquid with a faint mild odor.','Butylene Glycol, are clear, practically colorless, liquids. In cosmetics and personal care products, these ingredients are used in the formulation of hair and bath products, eye and facial makeup, fragrances, personal cleanliness products, and shaving and skin care products.','Butylene Glycol is used as solvents and viscosity decreasing agents in cosmetics and personal care products.','(+/-)-1,3-Butanediol, 1,3- Butanediol, 1,3-Butylene Glycol, 1,3-Dihydroxybutane, 1-MethyltrimethyleneGlycol, B-Butylene Glycol, (ñ)-butane-1,3-diol, 1,3-Butandiol, 1,3-Butanodiol.','Keep containers tightly closed ina col, well-ventilaed place. Handle and open container with care. Keep at temperatures betwe n 15 and 27 øC (60 and 80 øF).','[\"250 ml. Bottle\",\"1 kg. Bottle\",\"8 lb. HDPE Jug\",\"40 lb. Blue TH Pail\",\"400 lb. Steel Drum\",\"200 kg. Steel Drum\",\"460 lb. Steel B Drum\",\"460 lb. Steel W Drum\",\"460 lb. ST BLK Drum\"]','[\"Cosmetics\",\"food & bev.\"]','[\"Humectants\",\"solvents\"]','C4H10O2','[\"Origin: Synthetic\",\"Shelf life: 1 year from mfg. date\",\"Freight Classification: NON-REGULATED BY DOT, NMFC48580 S3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 109 \\u00f8C (228 \\u00f8F; 382 K)\",\"Melting Point: -50 \\u00f8C (-58 \\u00f8F; 223 K)\",\"API: NO\",\"Allergen: NO\",\"Hazmat: NO\",\"Molecular Weight: 90.12 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7361,'1,3 BUTYLENE GLYCOL COSMETIC GRADE','100007','GCC','107-88-0','1','13-butylene-glycol-cosmetic-grade','Clear, colorless, syrupy liquid, essentially odorless.','Butylene Glycol, are clear, practically colorless, liquids. In cosmetics and personal care products, these ingredients are used in the formulation of hair and bath products, eye and facial makeup, fragrances, personal cleanliness products, and shaving and skin care products.','Butylene Glycol is used as solvents and viscosity decreasing agents in cosmetics and personal care products.','(+/-)-1,3-Butanediol, 1,3- Butanediol, 1,3-Butylene Glycol, 1,3-Dihydroxybutane, 1-MethyltrimethyleneGlycol, B-Butylene Glycol, (ñ)-butane-1,3-diol, 1,3-Butandiol, 1,3-Butanodiol.','Keep containers tightly closed ina col, well-ventilaed place. Handle and open container with care. Keep at temperatures betwe n 15 and 27 øC (60 and 80 øF).','[\"250 ml. HDPE Bottle\",\"40 lb. Blue TH Pail\",\"1 lb. Bulk\"]','[\"Cosmetics\",\"food & bev.\"]','[\"Humectants\",\"solvents\"]','C4H10O2','[\"Origin: Synthetic\",\"Shelf life: 1 year from mfg. date\",\"Freight Classification: NON-REGULATED BY DOT, NMFC48580 S3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 121 \\u00f8C\",\"Melting Point: -50 \\u00f8C (-58 \\u00f8F; 223 K)\",\"API: NO\",\"Allergen: NO\",\"Hazmat: NO\",\"Molecular Weight: 90.121 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7362,'1,3 BUTYLENE GLYCOL TECHNICAL GRADE','100008','GCC','107-88-0','1','13-butylene-glycol-technical-grade','Clear, colorless, syrupy liquid, essentially odorless.',NULL,'1,3 Butylene Glycol is a viscosity decreasing component. Like other humectants, it forms a barrier which prevents the drying out of cosmetics. It prevents the assimilation of water from atmospheres of high humidity into film-forming preparations. Butylene Glycol prevents crystallization of insoluble components in cosmetic vehicles.','(+/-)-1,3-Butanediol, 1,3- Butanediol, 1,3-Butylene Glycol, 1,3-Dihydroxybutane, 1-MethyltrimethyleneGlycol, B-Butylene Glycol, (ñ)-butane-1,3-diol, 1,3-Butandiol, 1,3-Butanodiol.','Keep containers tightly closed ina col, well-ventilaed place. Handle and open container with care. Keep at temperatures betwe n 15 and 27 øC (60 and 80 øF).','[\"250 ml. HDPE Bottle\",\"460 lb. Steel Drum\",\"1 lb. Bulk\"]','[\"Cosmetics\"]','[\"Humectants\",\"solvents\",\"plasticizers\"]','C4H10O2','[\"Origin: Synthetic\",\"Shelf life: 1 year from mfg. date\",\"Freight Classification: NON-REGULATED BY DOT, NMFC48580 S3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 121 \\u00f8C (250 \\u00f8F) 134oC (closed cup)\",\"Melting Point: 20.4 \\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: NO\",\"Molecular Weight: 90.121 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7363,'16-METHYLHEPTADECANOIC ACID','100009','GCC','61332-02-3','1','16-methylheptadecanoic-acid','QC: IVORY PASTY SEMI-SOLID WITH FATTY ODOR',NULL,NULL,'SYN: TEGIN ISO, GLYCEROL FATTY ACID ESTER',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7364,'1-(CIS-3-CHLOROALLYL)-3,5,7-TRIAZA-1-AZONIA-ADAMANTANE CHLORIDE','100010','GCC','51229-78-8','1','1-cis-3-chloroallyl-357-triaza-1-azonia-adamantane','OFF-WHITE POWDER WITH SLIGHT AMINE-LIKE ODOR',NULL,NULL,'SYN: DOWICIL 75',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7365,'1-HYDROXYETHYLIDENE-1, 1-DIPHOSPHONIC ACID (AND) PHOSPHONIC ACID','100011','GCC','2809-21-4','1','1-hydroxyethylidene-1-1-diphosphonic-acid-and-phos','QC: CLEAR TO YELLOW LIQUID WITH CHARACTERISTIC ODOR.',NULL,NULL,'SYN: DEQUEST 2010',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7366,'1-HYDROXYOCTADECANE','100012','GCC','112-92-5','1','1-hydroxyoctadecane','QC: WHITE FLAKES, ODOR MILD OF FATTY ACIDS',NULL,NULL,NULL,NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7367,'20 %TERTIARY BUTYLATED HYDROQUINONE','100015','GCC','1948-33-0','1','20-tertiary-butylated-hydroquinone','White crystalline powder',NULL,'TBHQ antioxidant is readily soluble at use levels in fats and oils and in a number of food grade solvents. It can be applied by the basic techniques in general use for applying other food grade antioxidants to oils, fats, and foods.','20% Tertiary Butylated Hydroquinone; Uantox 20; Sustane 20; TBHQ; Banox 20 BA; Tenox TBHQ','Store in a tightly closed container. Store in a cool, dry, well-ventilated area. (25oC)','[\"1 lb. Bulk\"]','[\"Food & bev.\"]','[\"Antioxidants\"]','C10H14O2','[\"Origin: Synthetic\",\"Shelf life: 3 years from mfg. date if unopened\",\"Freight Classification: NON REGULATED CHEMICALS NOI CLASS 55\",\"Kosher Status: Not Kosher\",\"Flash Point: 150\\u00f8 C\",\"Melting Point: 126.5\\u00f8C to 128\\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 166.24 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7368,'2-(2-[4-(1,1,3,3-TETRAMETHYLBUTYL)PHENOXY]ETHOXY) ETHANOL','100016','GCC','9036-19-5','1','2-2-4-1133-tetramethylbutylphenoxyethoxy-ethanol','QC: CLEAR YELLOW LIQUID WITH MILD ODOR.',NULL,NULL,'SYN: TRITON X-15, UNITON X15, OCTYLPHENOL ETHOXYLATE,',NULL,'[null]','[\"Chem.proc.\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7369,'2,2,4 TRIMETHYLPENTANE','100017','GCC','9036-19-5','1','224-trimethylpentane','Clear, colorless liquid with Benzene-like odor (odor of gasoline).',NULL,'2,2,4-Trimethylpentane, also known asÿisooctaneÿorÿiso-octane, is anÿorganic compoundÿwith the formula. It is an important component ofÿgasoline, frequently used in relatively large proportions to increase theÿknockÿresistance of the fuel.','2,2,4 Trimethylpentane, Isooctane; Isobutyltrimethylmethane','Store in a segregated and approved area. Keep container in a cool, well-ventilated area. Keep container tightly closed and sealed until ready for use. Avoid all possible sources of ignition (spark or flame).','[\"350 lb. Drum\",\"1 lb. Bulk\"]','[\"Energy\"]','[\"Solvents\"]','C8H18','[\"Origin: Synthetic\",\"Shelf life: Limited\",\"Freight Classification: NMFC 48580 SUB 3 CLASS 55\",\"Kosher Status: Not Kosher\",\"Flash Point: -12 \\u00f8C (10 \\u00f8F; 261 K)\",\"Melting Point: -161oF, -107oC\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 158.28 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7370,'2-(2-HYDROXYETHYLAMINO) ETHANOL','100018','GCC','68585-44-4','1','2-2-hydroxyethylamino-ethanol','QC:',NULL,NULL,'SYN: STANDAPOL DEA; UNIPOL DEA',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7371,'2, 6, 8 - TRIMETHYLNONAN-4','100019','GCC','123-17-1','1','2-6-8-trimethylnonan-4','Clear to very pale yellow liquid',NULL,'Used in cleaning and degreasing materials for dewaxing and extraction in mining. Also, used in coatings, inks, and fragrances',NULL,'Keep container tightly closed. Store in a cool, dark and well-ventilated place. Store away from incompatible materials such as oxidizing agents.','[\"450 lb. Liquipak\",\"1 lb. Bulk\"]','[\"Industrial\",\"cosmetics\"]','[\"Solvents\",\"oating and sealants chemicals\",\"degreasers\"]','C12H26O','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NON-REGULATED BY DOT, NMFC48580 S3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 200\\u00f8C\",\"Melting Point: -75\\u00a7C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 186.33 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7372,'2,6-DI-TERT-BUTYL-4-METHYLPHENOL','100020','GCC','128-37-0','1','26-di-tert-butyl-4-methylphenol','WHITE CRYSTALLINE SOLID WITH CHARACTERISTIC ODOR.',NULL,NULL,'IONOL CP, BHT, BUTYLATED HYDROXYTOLUENE',NULL,'[null]','[\"Food & bev.\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7373,'2-ACRYLAMIDO-2-METHYLPROPANE SULFONIC ACID','100021','GCC','15214-89-8','1','2-acrylamido-2-methylpropane-sulfonic-acid','Colorless to light yellow liquid','Oil field applications: Polymers in oil field applications have to stand hostile environments and require thermal and hydrolytic stability and the resistance to hard water containing metal ions. Construction applications: Superplasticizers with AMPS are used to reduce water in concrete formulations. Benefits of these additives include improved strength, improved workability, improved durability of cement mixtures.','Nickname AMPS. Very efficient lubricant characteristics for skin care. Medical hydrogel: High water-absorbing and swelling capacity when AMPS is introduced to a hydrogel are keys to medical applications.','2-Acrylamindo-2-Methylpropane Sulfonic Acid; 2-Acrylamido-2-methylpropanesulfonic acid; 2-Acrylamido-2-methyl-1-propane sulfonic acid','Keep container tightly closed in a dry and well-ventilated place.','[\"40 lb. Pail\",\"405 lb. Steel Drum\",\"1 lb. Bulk\"]','[\"Cosmetics\",\"industrial\",\"pharmaceutical\"]','[\"Acidulants\",\"acrylates & methacrylates\"]','C7H13NO4S','[\"Origin: Synthetic\",\"Shelf life: 10 months from mfg. date\",\"Freight Classification: NON-REGULATED CHEMICALS N.O.I. CLASS 55\",\"Kosher Status: Not Kosher\",\"Flash Point: 195 \\u00f8C\",\"Melting Point: 160 \\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 207.25 g\\/mol-1\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7374,'2-BROMO-2-NITROPROPANE-1(AND) 3-DIOL','100022','GCC','52-51-7','1','2-bromo-2-nitropropane-1and-3-diol','White to yellow powder with characteristic odor.','The use of bronopol in personal care products (cosmetics, toiletries) has declined since the late 1980s due to the potential formation of nitrosamines.','Bronopol is used in consumer products as an effective preservative agent, as well as a wide variety of industrial applications (almost any industrial water system is a potential environment for bacterial growth, leading to slime and corrosion problems - in many of these systems Bronopol can be a highly effective treatment).','2-Bromo-2-Nitropropane-1,3Diol, Lexgard T/N: Bronopol','Keep container tightly closed in a dry and well-ventilated place.','[\"5 kg. HDPE OH Pail\",\"10 kg. HDPE OH Pail\",\"1 lb. Bulk\"]','[\"Pharmaceutical\",\"industrial\",\"cosmetics\"]','[\"Surfactants\"]','C3H6NO4Br','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NMFC 43940 SUB 2 CLASS 85\",\"Kosher Status: Not Kosher\",\"Flash Point: 170.3 \\u00f8C\",\"Melting Point: 130 - 133 \\u00f8C (266 - 271 \\u00f8F) - lit.\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 164.16 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7375,'2-DEOXY-D-GLUCOSE','100023','GCC','154-17-6','1','2-deoxy-d-glucose','White to yellow crystalline solid.',NULL,'2-DG has been used as a targeted optical imaging agent for fluorescentÿin vivoÿimaging. In clinical medical imaging (PET scanning),ÿfluorodeoxyglucoseÿis used, where one of the 2-hydrogens of 2-deoxy-D-glucose is replaced with the positron-emitting isotopeÿfluorine-18, which emits pairedÿgamma rays, allowing distribution of the tracer to be imaged by external gamma camera(s). This is increasingly done in tandem with aÿCTÿfunction which is part of the same PET/CT machine, to allow better localization of small-volume tissue glucose-uptake differences.','D-Glucose, 2-deoxy-; Deoxyglucose; 2-DG; 2-Deoxy-D-arabino-hexose;','Store at room temperature','[\"100 Gram HDPE WM Bottle\",\"1 lb. Bulk\"]','[\"Pharmaceutical\"]','[\"Gluconates\"]','C6H12O5','[\"Origin: Synthetic\",\"Shelf life: 1 year from mfg. date\",\"Freight Classification: NMFC 48580 SUB 3 CLASS 55\",\"Kosher Status: Not Kosher\",\"Flash Point: 202.3 \\u00f8C\",\"Melting Point: 146 to 147\\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 199.99 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7376,'2-ETHOXY ETHANOL REAGENT','100024','GCC','110-80-5','1','2-ethoxy-ethanol-reagent','Clear colorless liquid with pleasant odor.',NULL,'2-Ethoxyethanol, Reagant is a clear and colorless liquid that is water miscible and also referred to as ethyl cellosolve, a widely used solvent. It is used to dissolve chemically diverse compounds such as oils, resins, waxes among others.','2-2-Ethoxyethanol, Reagant, Cellosolve*; Ethylene Glycol Monoethyl Ether','Protect against physical damage. Store in a cool dry well ventilatd location away from any area where the fire hazards may be acute','[\"20 L. Pail\"]','[\"Pharmaceutical\",\"food & bev.\"]','[\"Solvent\",\"flavor & fragrance\"]','C4H10O2','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NMFC 43940 S 2 CL 85\",\"Kosher Status: Not Kosher\",\"Flash Point: 44 \\u00f8C\",\"Melting Point: -100OC\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 90.12 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7377,'2-ETHYL HEXANOL','100025','GCC','104-76-7','1','2-ethyl-hexanol','Clear liquid with characteristic odor.',NULL,'ÿIt is produced on a massive scale for use in numerous applications such as solvents, flavors, and fragrances and especially as a precursor for production of other chemicals such as emollients and plasticizers. It is encountered in natural plant fragrances, and the odor has been reported as \"heavy, earthy, and slightly floral\" for the Renantiomer and \"a light, sweet floral fragrance\" for the Senantiomer.','2-Ethyl Hexanol, Ethylhexyl Alcohol, 2-Ethyl-hexanol-1;Ethylhexyl alcohol;2-EH;Aerofroth 88;Octyl alcohol;Surfynol 104A;Hexanol, 2-ethyl-;Ethyl-1-hexanol,2-;Hexan-1-ol, 2-ethyl, Ethylhexanol;2-Ethyl-1-hexanol;2-Ethylhexan-1-ol','Store in a tightly cosed containers in a cool, dry, well ventilated area away from sources of heat and incompatible substances','[\"1 lb. Bulk\"]','[\"Cosmetics\"]','[\"Solvents\",\"flavors\",\"emollients\",\"plasticizers\"]','C8H18O','[\"Origin: Synthetic\",\"Shelf life: 5 Years from mfg. date\",\"Freight Classification: NMFC 43940 S 2 CL 85\",\"Kosher Status: Not Kosher\",\"Flash Point: 73o C\",\"Melting Point: -76\\u00ff\\u00f8C (-105\\u00ff\\u00f8F; 197\\u00ffK)\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 270.45 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7378,'2-ETHYLHEXYL ISONONANOATE','100026','GCC','71566-49-9','1','2-ethylhexyl-isononanoate','Clear colorless liquid.',NULL,'Fast spreading, dry emollient that can be used in facial care and baby care products. Provides a dry, skin feel in all skin care applications. Improves hair conditioning for shampoo and hair conditioners. Prevents clogging of aerosols and acts as a plasticizer resin in hairsprays. Offers good UV filter solubilizing properties for sun protection and after-sun products. Acts as a replacement for volatilesilicones in color cosmetic and anti-perspirant/deodorant applications.','2-Ethylhexyl Isononanoate, Phoenix Chem T/N: Pelemol 89, 2-ethylhexyl 7-methyloctanoate, Isononanoic acid, 2-ethylhexyl ester, 7-Methyloctanoic acid 2-ethylhexyl ester','Store in cool, dry conditions at a temperature between 15øC (59øF) – 25øC (77øF)','[\"250 ml. HDPE Bottle\",\"1 lb. Bulk\"]','[\"Cosmetics\"]','[\"Emollients\"]','C17H34O2','[\"Origin: Synthetic\",\"Shelf life: 12 Months from date of manufacture\",\"Freight Classification: NMFC 43940 SUB 2 CLASS 85\",\"Kosher Status: Not Kosher\",\"Flash Point: 260\\u00f8F ( 147.1 \\u00f8C )\",\"Melting Point: Not Measured\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 104.10 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7379,'2-ETHYLHEXYL SALICYLATE','100027','GCC','118-60-5','1','2-ethylhexyl-salicylate','QC: CLEAR COLORLESS TO YELLOWISH LIQUID WITH CHARACTERISTIC ODOR',NULL,NULL,'SYN: NEO HELIOPAN OS; ETHYLHEXYL SALICYLATE',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7380,'2-HYDROXYETHYL)(2-HYDROXYHEXADECYL) DIMETHYLAMMONIUM CHLORIDE','100028','GCC','84643-53-8','1','2-hydroxyethyl2-hydroxyhexadecyl-dimethylammonium-','QC: LIGHT YELLOW LIQUID WITH AMINE ODOR',NULL,NULL,'SYN: DEHYQUART E – CA, HYDROXYCETYL HYDROXYETHYL DIMONIUM CHLORIDE',NULL,'[null]','[\"Cosmetics\"]','[null]',NULL,'[null]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7381,'2-HYDROXY ISOBUTYRIC ACID','100029','GCC','594-61-6','1','2-hydroxy-isobutyric-acid','White odorless crystalline solid.',NULL,'Used as a paint and ink additive. For Cosmetics it is used as a Base, a Thickening Agent, a Pigment Wetting Agent, a Dispersant, a Solvent and an Emollient in Skin and Eye Make-Up and in Lipstick. Thickening Agent, Skin Conditioning Agent and Emollient in Skin Care Products. Used as a Lubricant for Plastics. Processing agent for rubber. Oiling agent for textiles.','2-Hydroxy Isobutyric Acid, 2-Hydroxy-2-methylpropionic acid; 2-Methyllactic acid; 2-Hydroxy-2-methylpropanoic acid','Store in a cool, dry place. Keep container closed when not in use. Refrigerator (approx 4 C)','[\"5 Gallon HDPE \\/Pail\",\"1 lb. Bulk\"]','[\"Pharmaceutical\",\"cosmetics\"]','[\"Thickeners\"]','C4H8O3','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NMFC 43940 SUB 2 CLASS 70 RV 2.15\",\"Kosher Status: Not Kosher\",\"Flash Point: 114\\u00f8C\\/12mm\",\"Melting Point: 76-80\\u00ff\\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 104.11 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7382,'2-HYDROXY ISOBUTYRIC ACID 99%','100030','GCC','594-61-6','1','2-hydroxy-isobutyric-acid-99','White odorless crystalline solid.',NULL,'Used as a paint and ink additive. For cosmetics it is used as a base, a thickening agent, a pigment wetting agent, a dispersant, a solvent and an emollient in skin and eye make-up and in lipstick. Thickening agent, skin conditioning agent and emollient in skin care products. Used as a lubricant for plastics. Processing agent for rubber and it is also used as an oiling agent for textiles.','2-Hydroxy Isobutiric Acid 99%, 2-Hydroxy-2-methylpropionic acid; 2-Methyllactic acid; 2-Hydroxy-2-methylpropanoic acid','Store in a cool, dry place. Keep container closed when not in use. Refrigerator (approx 4 C)','[\"1 lb. Bulk\"]','[\"Pharmaceutical\",\"cosmetics\"]','[\"Thickeners\"]','C4H8O3','[\"Origin: Synthetic\",\"Shelf life: 2 years from manufacture date.\",\"Freight Classification: NMFC 43940 SUB 2 CLASS 85\",\"Kosher Status: Not Kosher\",\"Flash Point: 114\\u00f8C\\/12mm\",\"Melting Point: 76-80 \\u00f8C\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 315.58 g\\/mol\"]','2025-04-10 07:11:54','2025-08-04 14:56:33'),(7383,'2-PHENOXYETHANOL','100031','GCC','122-99-6','1','2-phenoxyethanol','Clear to colorless liquid with mild rose odor.',NULL,'Bronidox 1160 was developed to provide a clean, odor- and color- stable product, and has since become the standard of superiority. Its mild, leaf-green, rose odor is consistently the same and affords particular utility in fragrance-applications where it is used as a olvent and as a rose note extender.','Brondix 1160, Emeressence 1160 Rose Ether, 2-Phenoxyethanol, Unisene PEH, Ethylene Glycol Phenyl Ether','Protect from freezing in storage and transit. Do not store below 50oF (10oC). Mix well before using and wash