INSERT INTO `products` VALUES (9490,'PEG 400 MONOSTEARATE','102327','GCC','9004-99-3','1','peg-400-monostearate','White solid',NULL,'Is an ester formed by the reaction of high purity stearic acid and PEG 400. PEG 400 MS is an emulsifier for oil-in-water emulsions and an auxiliary emulsifier for water-in-oil emulsions. In shampoos it is a hair conditioner and foam builder and known to improve cleansing action by preventing the redeposition of grease and dirt on the hair by a protective colloid effect. It is also used in formulations of ointments, creams, lotions and suspensions.','PEG 400 Monostearate; Unipeg 400M, JEEN T/N: Jeemate 400-DPS; PEG-8 Stearate; Polyglycol monostearate','Keep container tightly closed. Keep container in a cool, well-ventilated area.','[\"100 ml. HDPE Bottle\",\"39 lb. Open HD Pail\",\"40 lb. Open HD Pail\",\"450 lb. Steel Drum\",\"1 lb. Bulk\"]','[\"Cosmetics\"]','[\"Surfactants\",\"emollient & esters\",\"foam & viscosity boosters\"]','C4H9O2','[\"Origin: Synthetic\",\"Shelf life: 2 years from mfg. date\",\"Freight Classification: NMFC48580 S 3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 257\\u00f8C (494.6\\u00f8F)\",\"Melting Point: 30\\u00f8C (86\\u00f8F)\",\"API: NO\",\"Allergen: NO\",\"Hazmat: YES\",\"Molecular Weight: 89.11 g\\/mol\"]','2025-04-10 07:11:56','2025-08-04 14:56:33'),(9491,'PEG 400 MONOSTEARATE NF','102328','GCC','9004-99-3','1','peg-400-monostearate-nf','Soft waxy solid',NULL,'Used as an excipient in pharmaceuticals.','PEG 400 Monostearate NF; PEG 400 Monostearate; Unipeg 400M; PEG-8 Stearate; Polyglycol monostearate','Keep container tightly closed. Keep container in a cool, well-ventilated area.','[\"100 ml. HDPE Bottle\",\"250 ml. HDPE Bottle\",\"1 lb. Bulk\"]','[\"Pharmaceutical\"]','[\"Excipients\"]','C4H9O2','[\"Origin: Synthetic\",\"Shelf life: 2 years from mfg. date\",\"Freight Classification: NMFC48580 S 3 CL55\",\"Kosher Status: Not Kosher\",\"Flash Point: 257\\u00f8C (494.6\\u00f8F)\",\"Melting Point: 3